45: // The upstream HTTP filter manager class.
46: class UpstreamFilterManager : public Http::FilterManager {
47: public:
48:   UpstreamFilterManager(Http::FilterManagerCallbacks& filter_manager_callbacks,
49:                         Event::Dispatcher& dispatcher, OptRef<const Network::Connection> connection,
50:                         uint64_t stream_id, Buffer::BufferMemoryAccountSharedPtr account,
51:                         bool proxy_100_continue, uint32_t buffer_limit, UpstreamRequest& request)
52:       : FilterManager(filter_manager_callbacks, dispatcher, connection, stream_id, account,
53:                       proxy_100_continue, buffer_limit),
54:         upstream_request_(request) {}
55: 
56:   StreamInfo::StreamInfo& streamInfo() override {
57:     return upstream_request_.parent_.callbacks()->streamInfo();
58:   }
59:   const StreamInfo::StreamInfo& streamInfo() const override {
60:     return upstream_request_.parent_.callbacks()->streamInfo();
61:   }
62:   // Send local replies via the downstream HTTP filter manager.
63:   // Local replies will not be seen by upstream HTTP filters.
64:   void sendLocalReply(Http::Code code, absl::string_view body,
65:                       const std::function<void(Http::ResponseHeaderMap& headers)>& modify_headers,
66:                       const absl::optional<Grpc::Status::GrpcStatus> grpc_status,
67:                       absl::string_view details) override {
68:     state().decoder_filter_chain_aborted_ = true;
69:     state().encoder_filter_chain_aborted_ = true;
70:     state().encoder_filter_chain_complete_ = true;
71:     state().observed_encode_end_stream_ = true;
72:     // TODO(alyssawilk) this should be done through the router to play well with hedging.
73:     upstream_request_.parent_.callbacks()->sendLocalReply(code, body, modify_headers, grpc_status,
74:                                                           details);
75:   }
76:   void executeLocalReplyIfPrepared() override {}
77:   UpstreamRequest& upstream_request_;
78: };
