243:   const Formatter::HttpFormatterContext log_context{parent_.downstreamHeaders(),
244:                                                     upstream_headers_.get(),
245:                                                     upstream_trailers_.get(),
246:                                                     {},
247:                                                     access_log_type};
248: 
249:   for (const auto& upstream_log : parent_.config().upstream_logs_) {
250:     upstream_log->log(log_context, stream_info_);
