380: void UpstreamRequest::acceptHeadersFromRouter(bool end_stream) {
381:   ASSERT(!router_sent_end_stream_);
382:   router_sent_end_stream_ = end_stream;
383: 
384:   // Make sure that when we are forwarding CONNECT payload we do not do so until
385:   // the upstream has accepted the CONNECT request.
386:   // This must be done before conn_pool->newStream, as onPoolReady un-pauses for CONNECT
387:   // termination.
388:   auto* headers = parent_.downstreamHeaders();
389:   if (headers->getMethodValue() == Http::Headers::get().MethodValues.Connect) {
390:     paused_for_connect_ = true;
391:     // If this is a websocket upgrade request, pause the request until the upstream sends
392:     // the 101 Switching Protocols response code. Using the else logic here to obey CONNECT
393:     // method which is expecting 2xx response.
394:   } else if ((Runtime::runtimeFeatureEnabled(
395:                  "envoy.reloadable_features.check_switch_protocol_websocket_handshake")) &&
396:              Http::Utility::isWebSocketUpgradeRequest(*headers)) {
397:     paused_for_websocket_ = true;
398:   }
399: 
400:   // Kick off creation of the upstream connection immediately upon receiving headers.
401:   // In future it may be possible for upstream HTTP filters to delay this, or influence connection
402:   // creation but for now optimize for minimal latency and fetch the connection
403:   // as soon as possible.
404:   conn_pool_->newStream(this);
405: 
406:   if (parent_.config().upstream_log_flush_interval_.has_value()) {
407:     upstream_log_flush_timer_ = parent_.callbacks()->dispatcher().createTimer([this]() -> void {
408:       // If the request is complete, we've already done the stream-end upstream log, and shouldn't
409:       // do the periodic log.
410:       if (!streamInfo().requestComplete().has_value()) {
411:         upstreamLog(AccessLog::AccessLogType::UpstreamPeriodic);
412:         resetUpstreamLogFlushTimer();
413:       }
414:       // Both downstream and upstream bytes meters may not be initialized when
415:       // the timer goes off, e.g. if it takes longer than the interval for a
416:       // connection to be initialized; check for nullptr.
417:       auto& downstream_bytes_meter = stream_info_.getDownstreamBytesMeter();
418:       auto& upstream_bytes_meter = stream_info_.getUpstreamBytesMeter();
419:       const SystemTime now = parent_.callbacks()->dispatcher().timeSource().systemTime();
420:       if (downstream_bytes_meter) {
421:         downstream_bytes_meter->takeUpstreamPeriodicLoggingSnapshot(now);
422:       }
423:       if (upstream_bytes_meter) {
424:         upstream_bytes_meter->takeUpstreamPeriodicLoggingSnapshot(now);
425:       }
426:     });
427: 
428:     resetUpstreamLogFlushTimer();
429:   }
430: 
431:   filter_manager_->requestHeadersInitialized();
