476: 
477:   // Don't reset the stream if we're already done with it.
478:   if (upstreamTiming().last_upstream_tx_byte_sent_.has_value() &&
479:       upstreamTiming().last_upstream_rx_byte_received_.has_value()) {
480:     return;
481:   }
482: 
483:   if (span_ != nullptr) {
484:     // Add tags about the cancellation.
485:     span_->setTag(Tracing::Tags::get().Canceled, Tracing::Tags::get().True);
486:   }
487: 
488:   if (upstream_) {
489:     ENVOY_STREAM_LOG(debug, "resetting pool request", *parent_.callbacks());
490:     upstream_->resetStream();
491:     clearRequestEncoder();
492:   }
493:   reset_stream_ = true;
