524: void UpstreamRequest::onPerTryIdleTimeout() {
525:   ENVOY_STREAM_LOG(debug, "upstream per try idle timeout", *parent_.callbacks());
526:   if (per_try_timeout_) {
527:     // Disable the per try idle timer, so it does not trigger further retries
528:     per_try_timeout_->disableTimer();
529:   }
530:   stream_info_.setResponseFlag(StreamInfo::CoreResponseFlag::StreamIdleTimeout);
531:   parent_.onPerTryIdleTimeout(*this);
