534: void UpstreamRequest::onPerTryTimeout() {
535:   if (per_try_idle_timeout_) {
536:     // Delete the per try idle timer, so it does not trigger further retries.
537:     // The timer has to be deleted to prevent data flow from re-arming it.
538:     per_try_idle_timeout_.reset();
539:   }
540:   // If we've sent anything downstream, ignore the per try timeout and let the response continue
541:   // up to the global timeout
542:   if (!parent_.downstreamResponseStarted()) {
543:     ENVOY_STREAM_LOG(debug, "upstream per try timeout", *parent_.callbacks());
544: 
545:     stream_info_.setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamRequestTimeout);
546:     parent_.onPerTryTimeout(*this);
547:   } else {
548:     ENVOY_STREAM_LOG(debug,
549:                      "ignored upstream per try timeout due to already started downstream response",
550:                      *parent_.callbacks());
551:   }
552: }
