559: void UpstreamRequest::onPoolFailure(ConnectionPool::PoolFailureReason reason,
560:                                     absl::string_view transport_failure_reason,
561:                                     Upstream::HostDescriptionConstSharedPtr host) {
562:   recordConnectionPoolCallbackLatency();
563:   Http::StreamResetReason reset_reason = [](ConnectionPool::PoolFailureReason reason) {
564:     switch (reason) {
565:     case ConnectionPool::PoolFailureReason::Overflow:
566:       return Http::StreamResetReason::Overflow;
567:     case ConnectionPool::PoolFailureReason::RemoteConnectionFailure:
568:       return Http::StreamResetReason::RemoteConnectionFailure;
569:     case ConnectionPool::PoolFailureReason::LocalConnectionFailure:
570:       return Http::StreamResetReason::LocalConnectionFailure;
571:     case ConnectionPool::PoolFailureReason::Timeout:
572:       return Http::StreamResetReason::ConnectionTimeout;
573:     }
574:     PANIC_DUE_TO_CORRUPT_ENUM;
575:   }(reason);
576: 
577:   stream_info_.upstreamInfo()->setUpstreamTransportFailureReason(transport_failure_reason);
578: 
579:   // Mimic an upstream reset.
580:   onUpstreamHostSelected(host, false);
581:   onResetStream(reset_reason, transport_failure_reason);
582: }
