795: void UpstreamRequestFilterManagerCallbacks::resetStream(
796:     Http::StreamResetReason reset_reason, absl::string_view transport_failure_reason) {
797:   // The filter manager needs to disambiguate between a filter-driven reset,
798:   // which should force reset the stream, and a codec driven reset, which should
799:   // tell the router the stream reset, and let the router make the decision to
800:   // send a local reply, or retry the stream.
801:   bool is_codec_error;
802:   if (Runtime::runtimeFeatureEnabled("envoy.reloadable_features.report_stream_reset_error_code")) {
803:     is_codec_error = absl::StrContains(transport_failure_reason, "codec_error");
804:   } else {
805:     is_codec_error = transport_failure_reason == "codec_error";
806:   }
807:   if (reset_reason == Http::StreamResetReason::LocalReset && !is_codec_error) {
808:     upstream_request_.parent_.callbacks()->resetStream();
809:     return;
810:   }
811:   return upstream_request_.onResetStream(reset_reason, transport_failure_reason);
812: }
